static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    StandardMatrixMultiplicationCustomTilingData tiling;

    const gert::Shape *a_shape = context->GetInputShape(0);
    const gert::Shape *b_shape = context->GetInputShape(1);
    if (a_shape->GetOriginShape().GetDimNum() != 2 || b_shape->GetOriginShape().GetDimNum() != 2) {
        return ge::GRAPH_PARAM_INVALID;
    }

    const uint32_t M = static_cast<uint32_t>(a_shape->GetOriginShape().GetDim(0));
    const uint32_t K0 = static_cast<uint32_t>(a_shape->GetOriginShape().GetDim(1));
    const uint32_t K1 = static_cast<uint32_t>(b_shape->GetOriginShape().GetDim(0));
    const uint32_t N = static_cast<uint32_t>(b_shape->GetOriginShape().GetDim(1));
    if (K0 != K1) {
        return ge::GRAPH_PARAM_INVALID;
    }
    const uint32_t K = K0;

    TileChoice tc = ChooseTiles(M, N, K);

    // blocks based on tile grid
    const uint32_t tilesM = (tc.tm == 0) ? 1u : CeilDiv(M, tc.tm);
    const uint32_t tilesN = (tc.tn == 0) ? 1u : CeilDiv(N, tc.tn);
    uint32_t numTiles = tilesM * tilesN;

    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_M(M);
    tiling.set_N(N);
    tiling.set_K(K);
    tiling.set_tileM(tc.tm);
    tiling.set_tileN(tc.tn);
    tiling.set_tileK(tc.tk);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

